"""
Dashboard rendering engine for Crowdpulse.

Renders user dashboards with titles, descriptions, annotations,
and embedded widgets. All user-provided HTML content must be
sanitized before rendering.
"""

from typing import Dict, List, Optional
from security.sanitizer import sanitize_html


class DashboardRenderer:
    """Renders dashboard components with sanitized user content."""

    def __init__(self, template_dir: str = "rendering/templates"):
        self.template_dir = template_dir

    def render_title(self, raw_title: str) -> str:
        """Render a sanitized dashboard title."""
        return f'<h1 class="dashboard-title">{sanitize_html(raw_title)}</h1>'

    def render_description(self, raw_description: str) -> str:
        """Render a sanitized dashboard description."""
        return f'<div class="dashboard-desc">{sanitize_html(raw_description)}</div>'

    def render_annotation(self, raw_annotation: str, widget_id: str) -> str:
        """Render a sanitized annotation attached to a widget."""
        safe_content = sanitize_html(raw_annotation)
        return (
            f'<div class="annotation" data-widget="{widget_id}">'
            f'{safe_content}</div>'
        )

    def render_dashboard(self, dashboard: dict) -> str:
        """Render a complete dashboard page."""
        parts = []
        parts.append(self.render_title(dashboard.get('title', '')))
        parts.append(self.render_description(dashboard.get('description', '')))
        for widget in dashboard.get('widgets', []):
            parts.append(f'<div class="widget" id="widget-{widget["id"]}">')
            if 'annotation' in widget:
                parts.append(self.render_annotation(
                    widget['annotation'], widget['id']
                ))
            parts.append('</div>')
        return '\n'.join(parts)
